#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct {
    int starting;
    int no_of_edges;
} Node;

kernel void BFS_1(
    global Node* h_graph_nodes,
    global int* h_graph_edges,
    global char* h_graph_mask,
    global char* h_updating_graph_mask,
    global char* h_graph_visited,
    global int* h_cost,
    int no_of_nodes)
{
    int tid = get_global_id(0);

    if (tid >= no_of_nodes) return;

    if (h_graph_mask[tid] == 1) { 
        h_graph_mask[tid] = 0;
        int start = h_graph_nodes[tid].starting;
        int end = start + h_graph_nodes[tid].no_of_edges;

        for (int i = start; i < end; i++) {
            int id = h_graph_edges[i];
            if (h_graph_visited[id] == 0) {
                h_cost[id] = h_cost[tid] + 1;
                h_updating_graph_mask[id] = 1;
            }
        }
    }
}

kernel void BFS_2(
    global char* h_graph_mask,
    global char* h_updating_graph_mask,
    global char* h_graph_visited,
    global char* h_over,
    int no_of_nodes)
{
    int tid = get_global_id(0);

    if (tid >= no_of_nodes) return;

    if (h_updating_graph_mask[tid] == 1) {
        h_graph_mask[tid] = 1;
        h_graph_visited[tid] = 1;
        h_over[0] = 1;
        h_updating_graph_mask[tid] = 0;
    }
}
